// ── Seeded PRNG (Mulberry32) ──

function mulberry32(seed) {
  let s = seed | 0; // coerce to signed 32-bit int
  return function () {
    s = (s + 0x6D2B79F5) | 0;
    let t = Math.imul(s ^ (s >>> 15), 1 | s);
    t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}

// ── Dungeon Layout Generator ──

// Grid dimensions and spacing for room placement
const GRID_COLS = 4;
const GRID_ROWS = 4;
const CELL_SPACING = 20; // center-to-center distance between adjacent cells
const MIN_ROOM_SIZE = 12;
const MAX_ROOM_SIZE_INCLUSIVE = 15;
const PASSAGE_WIDTH = 4;

/**
 * Generate a deterministic dungeon layout from a numeric seed.
 * Returns { rooms: [...], passages: [...] }
 */
function generateLayout(seed) {
  const rng = mulberry32(seed);

  // Step 1 — place rooms by growth so every room is guaranteed connected
  // Start from a random seed cell, then repeatedly add a random unoccupied
  // neighbour of an existing room until we reach the target count.
  const grid = [];
  for (let r = 0; r < GRID_ROWS; r++) {
    grid[r] = new Array(GRID_COLS).fill(false);
  }
  const cellPositions = []; // [{r, c, x, z}]

  const startR = Math.floor(rng() * GRID_ROWS);
  const startC = Math.floor(rng() * GRID_COLS);
  const startZ = (startR - (GRID_ROWS - 1) / 2) * CELL_SPACING;
  const startX = (startC - (GRID_COLS - 1) / 2) * CELL_SPACING;
  grid[startR][startC] = true;
  cellPositions.push({ r: startR, c: startC, x: startX, z: startZ });

  // Target: at least 4 rooms, up to grid capacity
  const maxRooms = GRID_ROWS * GRID_COLS;
  const targetRooms = Math.max(4, Math.min(maxRooms, Math.floor(GRID_ROWS * GRID_COLS * 0.6)));

  while (cellPositions.length < targetRooms) {
    // Build frontier: unoccupied neighbours of existing rooms
    const frontier = [];
    for (const cell of cellPositions) {
      const dirs = [[-1, 0], [1, 0], [0, -1], [0, 1]];
      for (const [dr, dc] of dirs) {
        const nr = cell.r + dr;
        const nc = cell.c + dc;
        if (nr >= 0 && nr < GRID_ROWS && nc >= 0 && nc < GRID_COLS && !grid[nr][nc]) {
          frontier.push({ r: nr, c: nc });
        }
      }
    }

    if (frontier.length === 0) break; // grid is full

    // Pick a random frontier cell and add it
    const pick = frontier[Math.floor(rng() * frontier.length)];
    grid[pick.r][pick.c] = true;
    const px = (pick.c - (GRID_COLS - 1) / 2) * CELL_SPACING;
    const pz = (pick.r - (GRID_ROWS - 1) / 2) * CELL_SPACING;
    cellPositions.push({ r: pick.r, c: pick.c, x: px, z: pz });
  }

  // Step 2 — build connectivity via randomized DFS spanning tree
  // Adjacency: up/down/left/right
  const visited = new Set();
  const passages = []; // [{from, to}]  (from/to are indices into cellPositions)
  const key = (r, c) => `${r},${c}`;

  // Pick a random starting cell
  const startIdx = Math.floor(rng() * cellPositions.length);
  const stack = [startIdx];
  visited.add(startIdx);

  while (stack.length > 0) {
    const idx = stack[stack.length - 1];
    const cell = cellPositions[idx];
    const neighbors = [];

    // Check 4 neighbours
    const dirs = [[-1, 0], [1, 0], [0, -1], [0, 1]];
    for (const [dr, dc] of dirs) {
      const nr = cell.r + dr;
      const nc = cell.c + dc;
      if (nr >= 0 && nr < GRID_ROWS && nc >= 0 && nc < GRID_COLS && grid[nr][nc]) {
        const nIdx = cellPositions.findIndex(cp => cp.r === nr && cp.c === nc);
        if (nIdx >= 0 && !visited.has(nIdx)) {
          neighbors.push(nIdx);
        }
      }
    }

    if (neighbors.length > 0) {
      // Pick a random unvisited neighbor
      const nextIdx = neighbors[Math.floor(rng() * neighbors.length)];
      stack.push(nextIdx);
      visited.add(nextIdx);
      passages.push({ from: idx, to: nextIdx });
    } else {
      stack.pop();
    }
  }

  // Step 3 — add a few extra edges for loops (up to 30 % of possible edges)
  const possibleExtra = [];
  for (const cell of cellPositions) {
    const dirs = [[-1, 0], [1, 0], [0, -1], [0, 1]];
    for (const [dr, dc] of dirs) {
      const nr = cell.r + dr;
      const nc = cell.c + dc;
      if (nr >= 0 && nr < GRID_ROWS && nc >= 0 && nc < GRID_COLS && grid[nr][nc]) {
        const nIdx = cellPositions.findIndex(cp => cp.r === nr && cp.c === nc);
        const cIdx = cellPositions.indexOf(cell);
        if (nIdx >= 0 && cIdx < nIdx) { // avoid duplicates
          const exists = passages.some(p =>
            (p.from === cIdx && p.to === nIdx) || (p.from === nIdx && p.to === cIdx)
          );
          if (!exists) possibleExtra.push({ from: cIdx, to: nIdx });
        }
      }
    }
  }
  // Shuffle and pick a fraction
  for (let i = possibleExtra.length - 1; i > 0; i--) {
    const j = Math.floor(rng() * (i + 1));
    [possibleExtra[i], possibleExtra[j]] = [possibleExtra[j], possibleExtra[i]];
  }
  const extraCount = Math.min(Math.floor(possibleExtra.length * 0.3), possibleExtra.length);
  for (let i = 0; i < extraCount; i++) {
    passages.push(possibleExtra[i]);
  }

  // Step 4 — determine which sides each room uses for passage gaps
  // Map: cellIndex → Set of directions that have passages ('up','down','left','right')
  const passageSides = cellPositions.map(() => new Set());
  for (const p of passages) {
    const from = cellPositions[p.from];
    const to = cellPositions[p.to];
    if (to.r === from.r - 1) { passageSides[p.from].add('up'); passageSides[p.to].add('down'); }
    if (to.r === from.r + 1) { passageSides[p.from].add('down'); passageSides[p.to].add('up'); }
    if (to.c === from.c - 1) { passageSides[p.from].add('left'); passageSides[p.to].add('right'); }
    if (to.c === from.c + 1) { passageSides[p.from].add('right'); passageSides[p.to].add('left'); }
  }

  // Step 5 — build room objects with walls (gaps for passages)
  const rooms = cellPositions.map((cell, idx) => {
    const width = MIN_ROOM_SIZE + Math.floor(rng() * (MAX_ROOM_SIZE_INCLUSIVE - MIN_ROOM_SIZE + 1));
    const depth = MIN_ROOM_SIZE + Math.floor(rng() * (MAX_ROOM_SIZE_INCLUSIVE - MIN_ROOM_SIZE + 1));
    const halfW = width / 2;
    const halfD = depth / 2;
    const sides = passageSides[idx];
    const walls = [];
    const gap = PASSAGE_WIDTH;

    // North wall (z = cell.z - halfD), along x-axis
    if (!sides.has('up')) {
      walls.push({ x: cell.x, z: cell.z - halfD, length: width, axis: 'x' });
    } else {
      const segLen = (width - gap) / 2;
      walls.push({ x: cell.x - gap / 2 - segLen / 2, z: cell.z - halfD, length: segLen, axis: 'x' });
      walls.push({ x: cell.x + gap / 2 + segLen / 2, z: cell.z - halfD, length: segLen, axis: 'x' });
    }

    // South wall (z = cell.z + halfD)
    if (!sides.has('down')) {
      walls.push({ x: cell.x, z: cell.z + halfD, length: width, axis: 'x' });
    } else {
      const segLen = (width - gap) / 2;
      walls.push({ x: cell.x - gap / 2 - segLen / 2, z: cell.z + halfD, length: segLen, axis: 'x' });
      walls.push({ x: cell.x + gap / 2 + segLen / 2, z: cell.z + halfD, length: segLen, axis: 'x' });
    }

    // West wall (x = cell.x - halfW), along z-axis
    if (!sides.has('left')) {
      walls.push({ x: cell.x - halfW, z: cell.z, length: depth, axis: 'z' });
    } else {
      const segLen = (depth - gap) / 2;
      walls.push({ x: cell.x - halfW, z: cell.z - gap / 2 - segLen / 2, length: segLen, axis: 'z' });
      walls.push({ x: cell.x - halfW, z: cell.z + gap / 2 + segLen / 2, length: segLen, axis: 'z' });
    }

    // East wall (x = cell.x + halfW)
    if (!sides.has('right')) {
      walls.push({ x: cell.x + halfW, z: cell.z, length: depth, axis: 'z' });
    } else {
      const segLen = (depth - gap) / 2;
      walls.push({ x: cell.x + halfW, z: cell.z - gap / 2 - segLen / 2, length: segLen, axis: 'z' });
      walls.push({ x: cell.x + halfW, z: cell.z + gap / 2 + segLen / 2, length: segLen, axis: 'z' });
    }

    return { x: cell.x, z: cell.z, width, depth, walls };
  });

  // Step 6 — build passage objects with boundary walls
  const passageObjects = passages.map(p => {
    const from = cellPositions[p.from];
    const to = cellPositions[p.to];
    const walls = [];
    const halfGap = PASSAGE_WIDTH / 2;
    const fromRoom = rooms[p.from];
    const toRoom = rooms[p.to];

    // Horizontal passage (same row, different column)
    if (from.r === to.r) {
      const wallCentreX = (from.x + to.x) / 2;
      walls.push({ x: wallCentreX, z: from.z - halfGap, length: CELL_SPACING, axis: 'x' });
      walls.push({ x: wallCentreX, z: from.z + halfGap, length: CELL_SPACING, axis: 'x' });
    }

    // Vertical passage (same column, different row)
    if (from.c === to.c) {
      const wallCentreZ = (from.z + to.z) / 2;
      walls.push({ x: from.x - halfGap, z: wallCentreZ, length: CELL_SPACING, axis: 'z' });
      walls.push({ x: from.x + halfGap, z: wallCentreZ, length: CELL_SPACING, axis: 'z' });
    }

    // Corridor length: the gap between the two connected rooms' edges
    // This is used to trim passage-wall colliders so they don't intrude into room interiors
    // Horizontal passages use room widths (along x), vertical passages use depths (along z)
    const corridorLength = (from.r === to.r)
      ? CELL_SPACING - fromRoom.width / 2 - toRoom.width / 2
      : CELL_SPACING - fromRoom.depth / 2 - toRoom.depth / 2;

    return { x1: from.x, z1: from.z, x2: to.x, z2: to.z, walls, corridorLength };
  });

  return { rooms, passages: passageObjects };
}

// ── Exports ──

module.exports = {
  mulberry32,
  generateLayout,
  GRID_COLS,
  GRID_ROWS,
  CELL_SPACING,
  MIN_ROOM_SIZE,
  MAX_ROOM_SIZE_INCLUSIVE,
  PASSAGE_WIDTH
};

import * as THREE from 'three';
import { wallAABB, resolveWallCollision as resolveWallCollisionPure } from './collision.js';
import { PASSAGE_WIDTH } from './config.js';

// ── Visual constants ──

export const WALL_HEIGHT = 2.5;
export const WALL_THICKNESS = 0.4;
export const FLOOR_Y = 0.05; // slightly above background to avoid z-fighting
export const PASSAGE_WALL_HEIGHT = 1.5;
export const PASSAGE_WALL_THICKNESS = 0.3;

// ── Shared materials ──

export const floorMaterial = new THREE.MeshStandardMaterial({ color: 0x334155, roughness: 0.8 });
export const wallMaterial = new THREE.MeshStandardMaterial({ color: 0x475569, roughness: 0.7 });
export const passageFloorMaterial = new THREE.MeshStandardMaterial({ color: 0x2d3a4a, roughness: 0.8 });
const passageWallMaterial = new THREE.MeshStandardMaterial({ color: 0x3d4f63, roughness: 0.7 });
export const groundMaterial = new THREE.MeshStandardMaterial({ color: 0x0f172a, roughness: 1.0 });

/**
 * Remove all dungeon meshes from the scene and dispose geometries.
 * Shared materials are NOT disposed (they are reused across builds).
 *
 * @param {THREE.Scene} scene
 * @param {THREE.Mesh[]} dungeonMeshes - array to clear
 */
export function clearDungeon(scene, dungeonMeshes) {
	for (const mesh of dungeonMeshes) {
		if (scene) scene.remove(mesh);
		if (mesh.geometry) mesh.geometry.dispose();
		// Do NOT dispose materials — they are shared module-level constants
	}
	dungeonMeshes.length = 0;
}

/**
 * Build all dungeon geometry (rooms, passages, ground) from a server layout.
 *
 * @param {THREE.Scene} scene
 * @param {object} layout - { rooms, passages } from server
 * @returns {{ meshes: THREE.Mesh[], spawnPosition: {x: number, z: number} }}
 */
export function buildDungeon(scene, layout) {
	if (!layout || !layout.rooms || !layout.passages) {
		return { meshes: [], spawnPosition: { x: 0, z: 0 } };
	}

	const meshes = [];

	// Background ground (large flat plane behind everything)
	const groundGeo = new THREE.PlaneGeometry(200, 200);
	const ground = new THREE.Mesh(groundGeo, groundMaterial);
	ground.rotation.x = -Math.PI / 2;
	ground.position.y = 0;
	scene.add(ground);
	meshes.push(ground);

	// Spawn position: center of first room
	const spawnPosition = layout.rooms.length > 0
		? { x: layout.rooms[0].x, z: layout.rooms[0].z }
		: { x: 0, z: 0 };

	// ── Build rooms ──
	for (const room of layout.rooms) {
		// Room floor tile (raised slightly)
		const floorGeo = new THREE.BoxGeometry(room.width, 0.1, room.depth);
		const floorMesh = new THREE.Mesh(floorGeo, floorMaterial);
		floorMesh.position.set(room.x, FLOOR_Y, room.z);
		scene.add(floorMesh);
		meshes.push(floorMesh);

		// Room walls
		for (const wall of room.walls) {
			let wallGeo;
			let wallX, wallZ;

			if (wall.axis === 'x') {
				wallGeo = new THREE.BoxGeometry(wall.length, WALL_HEIGHT, WALL_THICKNESS);
				wallX = wall.x;
				wallZ = wall.z;
			} else {
				wallGeo = new THREE.BoxGeometry(WALL_THICKNESS, WALL_HEIGHT, wall.length);
				wallX = wall.x;
				wallZ = wall.z;
			}

			const wallMesh = new THREE.Mesh(wallGeo, wallMaterial);
			wallMesh.position.set(wallX, WALL_HEIGHT / 2 + FLOOR_Y, wallZ);
			scene.add(wallMesh);
			meshes.push(wallMesh);
		}
	}

	// ── Build passages ──
	for (const passage of layout.passages) {
		const dx = passage.x2 - passage.x1;
		const dz = passage.z2 - passage.z1;
		const dist = Math.hypot(dx, dz);

		// Passage floor strip
		const passageFloorGeo = new THREE.BoxGeometry(dist, 0.1, PASSAGE_WIDTH);
		const passageFloor = new THREE.Mesh(passageFloorGeo, passageFloorMaterial);
		const midX = (passage.x1 + passage.x2) / 2;
		const midZ = (passage.z1 + passage.z2) / 2;
		passageFloor.position.set(midX, FLOOR_Y, midZ);
		passageFloor.rotation.y = Math.atan2(dz, dx);
		scene.add(passageFloor);
		meshes.push(passageFloor);

		// Passage side walls
		for (const wall of passage.walls) {
			let wallGeo;
			let wallX, wallZ;

			if (wall.axis === 'x') {
				wallGeo = new THREE.BoxGeometry(wall.length, PASSAGE_WALL_HEIGHT, PASSAGE_WALL_THICKNESS);
				wallX = wall.x;
				wallZ = wall.z;
			} else {
				wallGeo = new THREE.BoxGeometry(PASSAGE_WALL_THICKNESS, PASSAGE_WALL_HEIGHT, wall.length);
				wallX = wall.x;
				wallZ = wall.z;
			}

			const wallMesh = new THREE.Mesh(wallGeo, passageWallMaterial);
			wallMesh.position.set(wallX, PASSAGE_WALL_HEIGHT / 2 + FLOOR_Y, wallZ);
			scene.add(wallMesh);
			meshes.push(wallMesh);
		}
	}

	return { meshes, spawnPosition };
}

/**
 * Build an array of wall AABB colliders from a server layout.
 *
 * @param {object} layout - { rooms, passages } from server
 * @returns {{ minX: number, maxX: number, minZ: number, maxZ: number }[]}
 */
export function buildWallColliders(layout) {
	const colliders = [];
	if (!layout || !layout.rooms || !layout.passages) return colliders;

	for (const room of layout.rooms) {
		for (const wall of room.walls) {
			colliders.push(wallAABB(wall, WALL_THICKNESS / 2));
		}
	}
	for (const passage of layout.passages) {
		for (const wall of passage.walls) {
			colliders.push(wallAABB({ ...wall, length: passage.corridorLength }, PASSAGE_WALL_THICKNESS / 2));
		}
	}

	return colliders;
}

/**
 * Resolve a proposed player position against a list of wall AABB colliders.
 *
 * @param {number} newX
 * @param {number} newZ
 * @param {{ minX: number, maxX: number, minZ: number, maxZ: number }[]} collidersRef
 * @returns {{ x: number, z: number }}
 */
export function resolveWallCollision(newX, newZ, collidersRef) {
	return resolveWallCollisionPure(newX, newZ, collidersRef);
}

// Server configuration constants

const TICK_RATE = 20; // times per second
const MOVE_SPEED = 12; // units per second — maximum player movement speed (matches client terminal velocity)
const MAX_ELAPSED_MS = 200; // maximum milliseconds of movement granted per request (prevents teleport via large time delta)
const DETECTION_RADIUS = 8; // units
const ENEMY_ATTACK_RANGE = 4; // units — must be this close to strike
const ENEMY_ATTACK_RECOVERY_MS = 1200; // cooldown after attack (hit or cancel)
const MAX_MAGIC_STONES = 100;
const MAGIC_STONES_REGEN_PER_TICK = 0.5;
const SUMMON_RADIUS = 10; // units — radial AoE
const ATTACK_RANGE = 5; // units — max distance to hit
const ATTACK_CONE_ANGLE = Math.PI / 2; // 90-degree forward cone
const STALE_THRESHOLD = 10000; // 10 seconds
const COOLDOWN_MS = 800; // server-side cooldown between uses of the same slot (milliseconds)
const BOUNDS_MARGIN = 2;
const SPAWN_PADDING = 2;
const DECK_MIN_SIZE = 4;
const DECK_MAX_SIZE = 12;
const MAX_HP = 100;
const RESPAWN_DELAY_MS = 3000;
const LOOT_LIFETIME_MS = 120000;
const LOOT_SPAWN_CHANCE = 0.5;
const STALE_CLEANUP_INTERVAL_MS = 5000;
const PERIODIC_SAVE_INTERVAL_MS = 30000;

const VICTORY_REWARD_ROTATION = [
  'flame_blade',
  'battle_familiar',
  'dungeon_drake',
];

module.exports = {
  TICK_RATE,
  MOVE_SPEED,
  MAX_ELAPSED_MS,
  DETECTION_RADIUS,
  ENEMY_ATTACK_RANGE,
  ENEMY_ATTACK_RECOVERY_MS,
  MAX_MAGIC_STONES,
  MAGIC_STONES_REGEN_PER_TICK,
  SUMMON_RADIUS,
  ATTACK_RANGE,
  ATTACK_CONE_ANGLE,
  STALE_THRESHOLD,
  COOLDOWN_MS,
  BOUNDS_MARGIN,
  SPAWN_PADDING,
  DECK_MIN_SIZE,
  DECK_MAX_SIZE,
  MAX_HP,
  RESPAWN_DELAY_MS,
  LOOT_LIFETIME_MS,
  LOOT_SPAWN_CHANCE,
  STALE_CLEANUP_INTERVAL_MS,
  PERIODIC_SAVE_INTERVAL_MS,
  VICTORY_REWARD_ROTATION
};

// ── Client configuration constants ──
// All magic numbers and tunable values extracted from main.js / dungeon.js.
// Import from here instead of defining inline.

// ── Deck ──

/** Minimum number of cards required in a deck to ready up */
export const DECK_MIN_SIZE = 4;

/** Maximum number of cards allowed in a deck */
export const DECK_MAX_SIZE = 12;

// ── Combat ──

/** Attack range in world units — matches server constant for attack range / warning circle radius */
export const ENEMY_ATTACK_RANGE = 4;

/** Maximum player HP */
export const MAX_HP = 100;

/** Maximum player Magic Stones */
export const MAX_MS = 100;

/** Window (ms) after a cardUsed hit during which we skip minion-damage effects */
export const CARD_HIT_GRACE_MS = 500;

// ── Visual effect durations ──

/** Weapon projectile: ms before auto-removal */
export const ATTACK_EFFECT_DURATION = 600;

/** Weapon projectile: units per second */
export const ATTACK_EFFECT_SPEED = 8;

/** Summon AoE: total lifetime (expand + fade) in ms */
export const SUMMON_EFFECT_DURATION = 1000;

/** Summon AoE: time to reach full radius in ms */
export const SUMMON_EXPAND_MS = 700;

/** Hit spark: ms before auto-removal */
export const HIT_SPARK_DURATION = 400;

/** Loot collection animation: ms for scale-up + fade */
export const LOOT_COLLECT_DURATION = 600;

/** Floating damage number: ms before auto-removal */
export const DAMAGE_NUMBER_DURATION = 1000;

// ── Camera ──

/** Camera field of view (degrees) */
export const CAMERA_FOV = 75;

/** Camera near clipping plane */
export const CAMERA_NEAR = 0.1;

/** Camera far clipping plane */
export const CAMERA_FAR = 1000;

/** Camera offset relative to player position {x, y, z} */
export const CAMERA_OFFSET = { x: 0, y: 5, z: 10 };

// ── Movement ──

/** Player movement speed (units/s) — matches server constant exactly */
export const MOVE_SPEED = 12;

/** Maximum ms of movement per frame — matches server constant to prevent drift */
export const MAX_ELAPSED_MS = 200;

// ── Dungeon ──

/** Width of passage corridors (matches server constant) */
export const PASSAGE_WIDTH = 4;

// ── Audio ──

/** Sound effect parameters per event type */
export const SOUND_CONFIG = {
	card:           { freq: 600, duration: 0.1 },
	enemyHit:       { freq: 300, duration: 0.15 },
	playerDamage:   { freq: 200, duration: 0.2 },
	loot:           { freq: 800, duration: 0.08 },
	victory:        { notes: [{ freq: 500, duration: 0.15 }, { freq: 700, duration: 0.15 }] },
	failure:        { notes: [{ freq: 400, duration: 0.2 }, { freq: 250, duration: 0.2 }] },
};

import { describe, it, expect } from 'vitest';
import {
  mulberry32,
  generateLayout,
  GRID_COLS,
  GRID_ROWS,
  CELL_SPACING,
  MIN_ROOM_SIZE,
  MAX_ROOM_SIZE_INCLUSIVE,
  PASSAGE_WIDTH
} from '../dungeon.js';

// ── mulberry32 PRNG ──

describe('mulberry32(seed)', () => {
  it('returns a function', () => {
    expect(typeof mulberry32(42)).toBe('function');
  });

  it('produces values in [0, 1)', () => {
    const rng = mulberry32(123);
    for (let i = 0; i < 100; i++) {
      const v = rng();
      expect(v).toBeGreaterThanOrEqual(0);
      expect(v).toBeLessThan(1);
    }
  });

  it('is deterministic for a fixed seed', () => {
    const a = mulberry32(99);
    const b = mulberry32(99);
    for (let i = 0; i < 50; i++) {
      expect(a()).toBe(b());
    }
  });

  it('produces different sequences for different seeds', () => {
    const a = mulberry32(1);
    const b = mulberry32(2);
    let differs = false;
    for (let i = 0; i < 100; i++) {
      if (a() !== b()) {
        differs = true;
        break;
      }
    }
    expect(differs).toBe(true);
  });
});

// ── generateLayout ──

describe('generateLayout(seed)', () => {
  it('returns an object with rooms and passages arrays', () => {
    const layout = generateLayout(42);
    expect(Array.isArray(layout.rooms)).toBe(true);
    expect(Array.isArray(layout.passages)).toBe(true);
  });

  it('is deterministic: same seed always produces identical output (deep equality)', () => {
    const a = generateLayout(777);
    const b = generateLayout(777);

    expect(a).toEqual(b);
  });

  it('produces at least 4 rooms', () => {
    const layout = generateLayout(1);
    expect(layout.rooms.length).toBeGreaterThanOrEqual(4);
  });

  it('produces at least 4 rooms across multiple seeds', () => {
